/**
 * Type surface for the pre-bundled v4 JS SDK.
 *
 * The runtime module (`./stagehand-v4.js`) is generated by
 * `scripts/build-v4-shim.ts`, which esbuild-bundles the TS-only `stagehand-v4`
 * SDK (from the sibling stagehand-v4 repo) into a single self-contained ESM
 * file. The committed `./stagehand-v4.js` is a stub that throws until that
 * build runs — see the README "Running CORE evals against v4" section.
 *
 * Only the slice the core adapter (`stagehand_v4_code.ts`) actually calls is
 * declared here, hand-mirrored from
 * `stagehand-v4/sdks/js/stagehand/client.ts`.
 */

export interface V4Coordinates {
  x?: number;
  y?: number;
  left?: number;
  top?: number;
  right?: number;
  bottom?: number;
}

export interface V4Locator {
  css?: string;
  xpath?: string;
  text?: string;
  title?: string;
  url?: string;
  targetId?: string;
  backendNodeId?: number;
  click(params?: Record<string, unknown>): Promise<unknown>;
  hover(params?: Record<string, unknown>): Promise<unknown>;
  fill(params: Record<string, unknown>): Promise<unknown>;
  type(params: Record<string, unknown>): Promise<unknown>;
  keyPress(params?: Record<string, unknown>): Promise<unknown>;
}

export interface V4EvaluateResult {
  value: unknown;
}

export interface V4ScreenshotResult {
  screenshot: string | null;
}

export interface V4SnapshotResult {
  formattedTree: string;
  xpathMap?: Record<string, unknown>;
  urlMap?: Record<string, unknown>;
}

export interface V4Page {
  targetId?: string;
  tabId?: number;
  page_idx?: number;
  url?: string;
  title?: string;
  goto(params: { url: string; waitUntil?: string }): Promise<V4Page>;
  /** LLM extraction (bench). Returns the extracted JSON object. */
  extract(params: {
    instruction?: string;
    goal?: string;
    schema?: Record<string, unknown>;
    locator?: Record<string, unknown>;
    options?: {
      api_key?: string;
      llm_model_name?: string;
      llm_session_id?: string;
    };
  }): Promise<Record<string, unknown>>;
  /** LLM action (bench). */
  act(params: {
    instruction?: string;
    action?: Record<string, unknown>;
    options?: {
      api_key?: string;
      llm_model_name?: string;
      maxSteps?: number;
    };
  }): Promise<Record<string, unknown>>;
  /** LLM observe (bench). Returns candidate action(s). */
  observe(params: {
    instruction?: string;
    options?: { api_key?: string; llm_model_name?: string };
  }): Promise<unknown>;
  reload(params?: Record<string, unknown>): Promise<unknown>;
  goBack(params?: Record<string, unknown>): Promise<unknown>;
  goForward(params?: Record<string, unknown>): Promise<unknown>;
  evaluate(params: {
    expression: string;
    arg?: unknown;
    awaitPromise?: boolean;
    returnByValue?: boolean;
  }): Promise<V4EvaluateResult>;
  screenshot(params?: Record<string, unknown>): Promise<V4ScreenshotResult>;
  snapshot(params?: Record<string, unknown>): Promise<V4SnapshotResult>;
  locate(params?: Record<string, unknown>): Promise<V4Locator>;
  click(params?: Record<string, unknown>): Promise<unknown>;
  hover(params?: Record<string, unknown>): Promise<unknown>;
  type(params: Record<string, unknown>): Promise<unknown>;
  keyPress(params?: Record<string, unknown>): Promise<unknown>;
  scroll(params?: Record<string, unknown>): Promise<unknown>;
  bringToFront(params?: Record<string, unknown>): Promise<V4Page>;
  close(params?: Record<string, unknown>): Promise<V4Page>;
}

export interface V4Browser {
  newPage(params?: { url?: string }): Promise<V4Page>;
  activePage(params?: Record<string, unknown>): Promise<V4Page | null>;
  pages(params?: Record<string, unknown>): Promise<V4Page[]>;
  setViewport(params: {
    width: number;
    height: number;
    deviceScaleFactor?: number;
  }): Promise<unknown>;
  close(params?: Record<string, unknown>): Promise<unknown>;
}

export interface V4ClientOptions {
  cdp_url?: string;
  [key: string]: unknown;
}

export class StagehandClient {
  constructor(options?: V4ClientOptions);
  readonly browser: V4Browser;
  connect(options?: V4ClientOptions): Promise<this>;
  close(): Promise<void>;
}
